package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreSurroundingSpaces_DefaultIsFalse() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_WithIgnoreSurroundingSpacesTrue() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null, true, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertTrue(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_StaticConstants() {
        assertFalse(CSVFormat.DEFAULT.getIgnoreSurroundingSpaces());
        assertTrue(CSVFormat.TDF.getIgnoreSurroundingSpaces());
    }
}
